import{_ as r,o as i,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026-05-22（週五）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-22.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-22.md"}'),a={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-22.md"};function n(s,t,e,d,g,h){return i(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="🫘-黃豆追蹤日報-—-2026-05-22-週五" tabindex="-1">🫘 黃豆追蹤日報 — 2026-05-22（週五） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026-05-22-週五" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026-05-22（週五）&quot;">​</a></h1><blockquote><p>查詢時間：2026-05-22 05:00 TST（2026-05-21 21:00 UTC） 報告類型：每日追蹤 ⚠️ CBOT 期貨時段說明：05:00 TST 週五凌晨 = 17:00 ET 週四，黃豆期貨已收盤</p></blockquote><hr><h2 id="📊-即時報價" tabindex="-1">📊 即時報價 <a class="header-anchor" href="#📊-即時報價" aria-label="Permalink to &quot;📊 即時報價&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>報價</th><th>日漲跌</th><th>查詢時間</th><th>來源</th></tr></thead><tbody><tr><td>CBOT 黃豆 Jul 2026 (ZSN26)</td><td>~1,194.32 USd/Bu</td><td>-0.45%</td><td>2026-05-21</td><td>TradingEconomics</td></tr><tr><td>WTI 原油</td><td>$97.12-$101.78/桶</td><td>—</td><td>2026-05-21</td><td>TradingEconomics</td></tr><tr><td>Brent 原油</td><td>$103.14-$108.09/桶</td><td>—</td><td>2026-05-21</td><td>NDTV Profit</td></tr><tr><td>DXY 美元指數</td><td>99.17-99.43</td><td>+0.08%</td><td>2026-05-21</td><td>TradingEconomics</td></tr><tr><td>天然氣 Henry Hub</td><td>$3.02/MMBtu</td><td>+10.98% 月</td><td>2026-05-21</td><td>TradingEconomics</td></tr><tr><td>尿素（合成）</td><td>~$864/噸（美國零售）</td><td>+50% 月</td><td>2026-04/05</td><td>DTN/World Bank</td></tr><tr><td>BDI 波羅的海乾散貨指數</td><td>2,964 點</td><td>-1.4%</td><td>2026-05-21</td><td>TradingView</td></tr></tbody></table><blockquote><p><strong>查詢時間（TST）</strong>：2026-05-22 05:00</p></blockquote><hr><h2 id="🔍-敘事延續-伊朗談判突破預期-→-油價回落-→-能源成本壓力紓解-但黃豆仍在-1-194-附近震盪" tabindex="-1">🔍 敘事延續：伊朗談判突破預期 → 油價回落 → 能源成本壓力紓解，但黃豆仍在 $1,194 附近震盪 <a class="header-anchor" href="#🔍-敘事延續-伊朗談判突破預期-→-油價回落-→-能源成本壓力紓解-但黃豆仍在-1-194-附近震盪" aria-label="Permalink to &quot;🔍 敘事延續：伊朗談判突破預期 → 油價回落 → 能源成本壓力紓解，但黃豆仍在 $1,194 附近震盪&quot;">​</a></h2><p><strong>本日核心</strong>：CBOT 黃豆 Jul 續跌至 ~1,194 USd/Bu（-0.45%），延續昨日 -0.45% 跌幅。三重壓力持續：① 川習會 $17B 農業承諾已在 5/18 反映，後續無新催化；② 巴西出口競爭激烈，全球供應充足；③ FOMC 鷹派 + Warsh 明日就任 → 美元偏強。但下行有支撐：伊朗談判突破 → 油價從 $101 回落至 $97-98 → 能源成本壓力紓解；USDA 種植進度大幅領先（67% vs 五年均值 53%）→ 利空有限。</p><p><strong>關鍵變化</strong>：</p><ul><li>天然氣 Henry Hub 升至 $3.02（月漲 +10.98%）→ 農業能源成本上升</li><li>尿素美國零售價 $864/噸（月漲 +50%）→ 化肥成本飆升</li><li>BDI 跌至 2,964（-1.4%）→ 海運成本從高檔回落</li><li>中國上週採購 14.5M bu 美國黃豆（25-26 年度），+2.4M bu（26-27 年度）</li></ul><hr><h2 id="_8-項追蹤指標" tabindex="-1">8 項追蹤指標 <a class="header-anchor" href="#_8-項追蹤指標" aria-label="Permalink to &quot;8 項追蹤指標&quot;">​</a></h2><h3 id="_1-usda-種植進度報告-每週" tabindex="-1">1. USDA 種植進度報告（每週） <a class="header-anchor" href="#_1-usda-種植進度報告-每週" aria-label="Permalink to &quot;1. USDA 種植進度報告（每週）&quot;">​</a></h3><ul><li><strong>種植進度</strong>（截至 5/17）：67% 黃豆已播種（前週 48%），高於五年均值 53%</li><li><strong>出芽率</strong>：32% 已出芽（前週 23%，五年均值 23%）</li><li><strong>個別州更新</strong>： <ul><li>Wisconsin：54%（前週 28%，+26 百分點，大幅跳升）</li><li>Michigan：37%（前週 12%，+25 百分點，追趕但仍落後五年均值 46%）</li><li>18 州中 7 州種植率 ≥20%</li></ul></li><li><strong>變化</strong>：🟢 <strong>大幅領先且加速</strong> — Michigan 從 12% 跳至 37%（+25pp），但仍落後</li><li><strong>分析</strong>：種植順利 → 供應預期增加 → 利空；但 Michigan 落後需持續關注</li><li><strong>查詢時間</strong>：2026-05-20</li><li>來源：DTN/Progressive Farmer (2026-05-20)、RFD TV (2026-05-20)、Southeast AgNet (2026-05-20)</li></ul><h3 id="_2-巴西供應-收割-出口-豐收" tabindex="-1">2. 巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#_2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;2. 巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><ul><li><strong>CONAB</strong>（5 月）：2025/26 產量 180.13M 噸（+0.5% vs 前估，+5% YoY）</li><li><strong>StoneX</strong>（5 月）：下修至 177.8M 噸（南大河乾旱）</li><li><strong>出口</strong>：CONAB 預測 116M 噸（歷史新高，+7.25% YoY）</li><li><strong>2026/27 展望</strong>：USDA 預估巴西產量 186M 噸（+8M vs 本季）</li><li><strong>巴西農民困境</strong>：低黃豆價格 + 高生產成本 + 弱港口溢價 → 利潤壓縮 → 擴種放緩</li><li><strong>變化</strong>：🟡 無重大變化 — 本季已收割完成，關注下季播種</li><li><strong>查詢時間</strong>：2026-05-19</li><li>來源：CONAB (2026-05)、Caixin Global (2026-05-18)、Farmdocdaily (2026-03)</li></ul><h3 id="_3-尿素價格-多單訊號" tabindex="-1">3. 尿素價格 + 多單訊號 <a class="header-anchor" href="#_3-尿素價格-多單訊號" aria-label="Permalink to &quot;3. 尿素價格 + 多單訊號&quot;">​</a></h3><ul><li><strong>美國零售尿素</strong>：~$864/噸（2026 年 4-5 月），月漲 +50%</li><li><strong>全球尿素</strong>：4 月飆至 $700+/噸（五週內 +50%），因荷莫茲海峽封鎖 + 地緣風險</li><li><strong>World Bank 預測</strong>：2026 年全球肥料價格漲 30%+，尿素年底可能 $675/噸（較 2025 +60%）</li><li><strong>荷莫茲效應</strong>：全球 ~30% 化肥出口經過海峽，成本持續高檔</li><li><strong>變化</strong>：🔴 <strong>大幅飆升</strong> — 尿素從 $577/噸（5/15 報價）升至 $864/噸（美國零售），月漲 50%</li><li><strong>查詢時間</strong>：2026-05</li><li>來源：DTN Progressive Farmer (2026-04-08)、World Bank/EcoFin (2026-05)、Metals-Hub (2026-05)</li></ul><h3 id="_4-荷莫茲海峽通航狀態" tabindex="-1">4. 荷莫茲海峽通航狀態 <a class="header-anchor" href="#_4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;4. 荷莫茲海峽通航狀態&quot;">​</a></h3><ul><li>🔴 <strong>伊朗建立「波斯灣海峽管理局」（PGSA）— 實質控制海峽</strong>：</li><li><strong>PGSA 運作</strong>（5/18 起）：伊朗要求船隻取得授權並支付過路費（最高 $200 萬人民幣/加密貨幣）</li><li><strong>IRGC 聲稱</strong>：5/20 單日協調 26 艘船隻通過海峽</li><li><strong>美國反制</strong>：4/13 起對伊朗港口實施「反封鎖」，已改道 90 艘商船、攔截 4 艘</li><li><strong>5/20 事件</strong>：伊朗油輪 CELESTIAL SEA 在阿曼灣被美軍攔截</li><li><strong>川普</strong>：反對任何過路費制度，稱海峽是國際水域</li><li><strong>UAE</strong>：公開譴責伊朗主張為「白日夢」</li><li><strong>對黃豆影響</strong>：油價從 $101 回落至 $97-98（因談判突破預期），但海峽實質封閉未變</li><li><strong>變化</strong>：🟡 <strong>制度化控制升級但談判突破預期</strong> — PGSA 是新發展，但談判突破可能改變格局</li><li><strong>查詢時間</strong>：2026-05-21</li><li>來源：RFE/RL (2026-05-21)、Democracy Now (2026-05-21)、PBS (2026-05-20)、Times of Israel (2026-05-20)</li></ul><h3 id="_5-中美貿易-中國進口" tabindex="-1">5. 中美貿易 + 中國進口 <a class="header-anchor" href="#_5-中美貿易-中國進口" aria-label="Permalink to &quot;5. 中美貿易 + 中國進口&quot;">​</a></h3><ul><li>🟢 <strong>中國上週採購 14.5M bu 美國黃豆</strong>（25-26 年度），+2.4M bu（26-27 年度）</li><li><strong>週出口銷售</strong>：351,400 噸（12.9M bu），較前週大增，較四周均值 +62%</li><li><strong>年度承諾</strong>：中國 2026-2028 每年購買至少 25M 噸美國黃豆 + $17B 其他農產品</li><li><strong>質疑</strong>：SCMP 報導——承諾「preliminary」+ 歷史上中國承諾常未完全兌現</li><li><strong>實際執行情況</strong>：1-3 月美國對華黃豆銷售年減 48%（S&amp;P Global）</li><li><strong>Farm Progress</strong>：黃豆可能因中國採購反彈至 $13+，但需觀察後續採購</li><li><strong>變化</strong>：🟢 <strong>本週銷售數據正面</strong> — 351,400 噸較四周均值 +62%，但持續性待觀察</li><li><strong>查詢時間</strong>：2026-05-21</li><li>來源：DTN/Progressive Farmer (2026-05-21)、Farm Progress (2026-05)、SCMP (2026-05-16)、Brownfield Ag News (2026-05-20)</li></ul><h3 id="_6-天然氣價格" tabindex="-1">6. 天然氣價格 <a class="header-anchor" href="#_6-天然氣價格" aria-label="Permalink to &quot;6. 天然氣價格&quot;">​</a></h3><ul><li><strong>Henry Hub</strong>：$3.02/MMBtu（月漲 +10.98%），突破 $3 心理關口</li><li><strong>EIA STEO 預測</strong>：Q2 均價 $2.83/MMBtu</li><li><strong>趨勢</strong>：從 5 月中旬 $2.96 升至 $3.02，持續上行</li><li><strong>影響</strong>：天然氣是氮肥（尿素）主要原料 → 天然氣漲 → 化肥成本漲 → 農業成本壓力</li><li><strong>變化</strong>：🔴 <strong>突破 $3 關口</strong> — 月漲 11%，推升化肥成本</li><li><strong>查詢時間</strong>：2026-05-21</li><li>來源：TradingEconomics (2026-05-21)、Rigzone/EIA (2026-05-20)</li></ul><h3 id="_7-聖嬰-拉尼娜氣候風險" tabindex="-1">7. 聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#_7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;7. 聖嬰/拉尼娜氣候風險&quot;">​</a></h3><ul><li><strong>變化</strong>：⚪ 本日無重大更新 — 待下季氣候報告</li><li><strong>查詢時間</strong>：2026-05-22</li></ul><h3 id="_8-cbot-價格區間-海運成本" tabindex="-1">8. CBOT 價格區間 + 海運成本 <a class="header-anchor" href="#_8-cbot-價格區間-海運成本" aria-label="Permalink to &quot;8. CBOT 價格區間 + 海運成本&quot;">​</a></h3><ul><li><strong>Jul 2026</strong>：~1,194.32 USd/Bu（-0.45%），從昨日 ~1,200 續跌</li><li><strong>技術面</strong>：支撐 1,180-1,200¢，壓力 1,220-1,240¢</li><li><strong>新作物 Nov</strong>：觸三年新高 &gt;$12/bu（受 WASDE 利多）</li><li><strong>BDI</strong>：2,964 點（-1.4%），從 5/15 高點 3,151 回落 <ul><li>Capesize：4,834（-0.9%），日均收益 $40,335</li><li>Panamax：2,276（-4.1%），日均收益 $20,458（糧食運輸主要船型）</li></ul></li><li><strong>變化</strong>：🟡 <strong>黃豆續跌 + Panamax 海運成本回落</strong> — 從週一高點 ~1,245 回落至 ~1,194，跌幅 ~4.1%</li><li><strong>查詢時間</strong>：2026-05-21</li><li>來源：TradingEconomics (2026-05-21)、TradingView (2026-05-21)、Baird Maritime (2026-05-21)</li></ul><hr><h2 id="📰-即時新聞-5-條" tabindex="-1">📰 即時新聞（5 條） <a class="header-anchor" href="#📰-即時新聞-5-條" aria-label="Permalink to &quot;📰 即時新聞（5 條）&quot;">​</a></h2><ol><li><strong>DTN/Progressive Farmer (2026-05-21)</strong>：July soybeans biding time, awaiting fresh catalysts — 1,194 USd/Bu</li><li><strong>Farm Progress (2026-05)</strong>：Soybeans could rally to above $13 if China purchases materialize</li><li><strong>SCMP (2026-05-16)</strong>：China-US farm deal depends on math — analysts skeptical of commitments</li><li><strong>Brownfield Ag News (2026-05-20)</strong>：Big week for old crop corn export sales, soybean sales also rise</li><li><strong>World Bank/EcoFin (2026-05)</strong>：Fertilizer prices could rise more than 30% in 2026, urea leading rally</li></ol><hr><h2 id="📊-情景分析" tabindex="-1">📊 情景分析 <a class="header-anchor" href="#📊-情景分析" aria-label="Permalink to &quot;📊 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>發生機率</th><th>價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>伊朗和談成功 + 海峽重開 + 中國採購落實</td><td>25%</td><td>+8-12%（至 ~1,300-1,360¢）</td><td>能源成本暴跌 + 化肥降價 + 需求大增</td></tr><tr><td>海峽持續封閉 + 種植順利 + 中國持續採購</td><td>50%</td><td>持平至 -2%（1,180-1,220¢）</td><td>供應充足 vs 能源成本高檔拉鋸</td></tr><tr><td>FOMC 升息 + 美元大幅走強 + 中國延遲</td><td>25%</td><td>-3-5%（至 ~1,150-1,180¢）</td><td>出口競爭力下降 + 資金外流</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-21): Soybeans 1,194.32 (-0.45%)</li><li>DTN/Progressive Farmer (2026-05-20): USDA crop progress — Wisconsin 54%, Michigan 37%</li><li>RFD TV (2026-05-20): Soybean planting progress by state</li><li>Southeast AgNet (2026-05-20): USDA reports strong corn/soybean planting progress</li><li>CONAB (2026-05): Brazil soybean production 180.13M tons</li><li>DTN/Progressive Farmer (2026-05-21): July soybeans 1,194, awaiting catalysts</li><li>Farm Progress (2026-05): Soybeans could rally above $13 on China purchases</li><li>SCMP (2026-05-16): China-US farm deal depends on math</li><li>Brownfield Ag News (2026-05-20): Export sales rise, soybean sales +62% vs 4-week avg</li><li>TradingEconomics (2026-05-21): Natural gas $3.02 (+10.98% monthly)</li><li>Rigzone/EIA (2026-05-20): EIA lowers Henry Hub price forecast</li><li>DTN Progressive Farmer (2026-04-08): Urea +50% in 5 weeks</li><li>World Bank/EcoFin (2026-05): Fertilizer prices could rise 30%+ in 2026</li><li>RFE/RL (2026-05-21): Iran PGSA toll system in Strait of Hormuz</li><li>TradingView (2026-05-21): Baltic Dry Index 2,964 (-1.4%)</li></ol>',38)])])}const b=r(a,[["render",n]]);export{c as __pageData,b as default};
